<?php namespace App\Repositories\Inventory;use App\Repositories\BaseRepository;use App\Models\Inventory\PurchaseOrder;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class PurchaseOrderRepository extends BaseRepository{    public function __construct(PurchaseOrder $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByOrderNo(string $orderNo): ?PurchaseOrder    {        return $this->query()->where('order_no', $orderNo)->first();    }    public function findByVendor(int $vendorId): Collection    {        return $this->findByField('vendor_id', $vendorId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('order_date', [$startDate, $endDate])->get();    }    public function getPendingOrders(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getApprovedOrders(): Collection    {        return $this->query()->where('status', 'approved')->get();    }    public function getReceivedOrders(): Collection    {        return $this->query()->where('status', 'received')->get();    }    public function approveOrder(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function receiveOrder(int $id): bool    {        return $this->update($id, ['status' => 'received', 'received_at' => now()]);    }    public function cancelOrder(int $id, string $reason = null): bool    {        $data = ['status' => 'cancelled'];        if ($reason) {            $data['cancellation_reason'] = $reason;        }        return $this->update($id, $data);    }    public function searchOrders(string $keyword): Collection    {        return $this->query()->where('order_no', 'like', "%{$keyword}%")->orWhere('notes', 'like', "%{$keyword}%")->get();    }    public function getByTotalAmountRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('total_amount', [$min, $max])->get();    }}